+        Err(e) if e.kind() == std::io::ErrorKind::NotFound => (
+            StatusCode::NOT_FOUND,
+            format!("template not found: {template}"),
+        )
+            .into_response(),
+        Err(e) => {
+            tracing::warn!(
+                "OBS テンプレ index.html 読み込み失敗 {}: {e}",
